import{_ as t,o as d,c as o,ag as r}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"MCP Tool Reference","description":"","frontmatter":{},"headers":[],"relativePath":"guide/mcp-api-tool-reference.md","filePath":"guide/mcp-api-tool-reference.md"}'),a={name:"guide/mcp-api-tool-reference.md"};function i(s,e,c,n,l,h){return d(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="mcp-tool-reference" tabindex="-1">MCP Tool Reference <a class="header-anchor" href="#mcp-tool-reference" aria-label="Permalink to &quot;MCP Tool Reference&quot;">​</a></h1><p>This page provides the complete input schema and parameter details for every tool available through the TeamCentral MCP API. For an overview of tools and how to get started, see <a href="./mcp-api.html">MCP API</a>.</p><h2 id="data-models" tabindex="-1">Data Models <a class="header-anchor" href="#data-models" aria-label="Permalink to &quot;Data Models&quot;">​</a></h2><h3 id="get-data-models" tabindex="-1"><code>get_data_models</code> <a class="header-anchor" href="#get-data-models" aria-label="Permalink to &quot;`get_data_models`&quot;">​</a></h3><p>Returns a list of Data Models that have been configured.</p><p><strong>Parameters:</strong> None</p><hr><h3 id="get-data-model-properties" tabindex="-1"><code>get_data_model_properties</code> <a class="header-anchor" href="#get-data-model-properties" aria-label="Permalink to &quot;`get_data_model_properties`&quot;">​</a></h3><p>Gets the properties of a Data Model. Must first call <code>get_data_models</code> to get a <code>dataModelId</code>.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr></tbody></table><h2 id="entity-lookup-query" tabindex="-1">Entity Lookup &amp; Query <a class="header-anchor" href="#entity-lookup-query" aria-label="Permalink to &quot;Entity Lookup &amp; Query&quot;">​</a></h2><h3 id="lookup-by-keyword" tabindex="-1"><code>lookup_by_keyword</code> <a class="header-anchor" href="#lookup-by-keyword" aria-label="Permalink to &quot;`lookup_by_keyword`&quot;">​</a></h3><p>Searches for foreign key-related entities by keyword. Must first call <code>get_data_models</code> to get an <code>entityType</code> and <code>entitySubType</code>, or get them from <code>get_data_model_properties</code>. If multiple entities are returned, the user should choose which one to use.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>searchValue</code></td><td>string</td><td>Yes</td><td>The keyword to search for</td></tr><tr><td><code>entityType</code></td><td>string</td><td>No</td><td>Entity type from <code>get_data_models</code></td></tr><tr><td><code>entitySubType</code></td><td>string</td><td>No</td><td>Entity sub-type from <code>get_data_models</code></td></tr><tr><td><code>limit</code></td><td>integer</td><td>No</td><td>Max results to return (1–100, default 10)</td></tr></tbody></table><hr><h3 id="query-entities" tabindex="-1"><code>query_entities</code> <a class="header-anchor" href="#query-entities" aria-label="Permalink to &quot;`query_entities`&quot;">​</a></h3><p>Queries for entities using filters, sorting, pagination, and optional property selection. This is the most flexible query tool, supporting complex filter groups with AND/OR logic and property-to-property comparisons.</p><p><strong>Prerequisites:</strong></p><ul><li>Call <code>get_data_models</code> to get a <code>dataModelId</code></li><li>Call <code>get_data_model_properties</code> to find valid property names for filters</li><li>Call <code>lookup_by_keyword</code> if a property is a foreign key, to get the entity ID (GUID) for comparison</li></ul><p>If results contain File entities with an <code>externalFileLocation</code> property, use <code>get_file_text</code> to extract readable content.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr><tr><td><code>queryParameterGroups</code></td><td>array</td><td>No</td><td>Filter groups (see <a href="#query-parameter-groups">Query Parameter Groups</a> below)</td></tr><tr><td><code>paging</code></td><td>object</td><td>No</td><td>Pagination settings (see <a href="#paging">Paging</a> below)</td></tr><tr><td><code>sortCondition</code></td><td>object</td><td>No</td><td>Sort settings (see <a href="#sort-condition">Sort Condition</a> below)</td></tr><tr><td><code>countOnly</code></td><td>boolean</td><td>No</td><td>When <code>true</code>, returns only the count without entity data (default <code>false</code>)</td></tr><tr><td><code>properties</code></td><td>string[]</td><td>No</td><td>Property names to include in results. Only these fields (plus <code>id</code>) are returned. Omit to return all fields.</td></tr></tbody></table><h4 id="query-parameter-groups" tabindex="-1">Query Parameter Groups <a class="header-anchor" href="#query-parameter-groups" aria-label="Permalink to &quot;Query Parameter Groups&quot;">​</a></h4><p>Each group contains an array of filter parameters combined with AND/OR logic. Multiple groups are supported for complex queries.</p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>andOrOperator</code></td><td>enum</td><td>No</td><td><code>And</code> or <code>Or</code> (default <code>And</code>)</td></tr><tr><td><code>parameters</code></td><td>array</td><td>No</td><td>Array of filter parameters (see below)</td></tr></tbody></table><p><strong>Filter Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>operator</code></td><td>enum</td><td>Yes</td><td>One of: <code>EqualTo</code>, <code>NotEqualTo</code>, <code>GreaterThan</code>, <code>GreaterThanEqualTo</code>, <code>LessThan</code>, <code>LessThanEqualTo</code>, <code>Contains</code>, <code>StartsWith</code>, <code>NotStartsWith</code>, <code>EndsWith</code>, <code>NotEndsWith</code></td></tr><tr><td><code>propertyName</code></td><td>string</td><td>Yes</td><td>A valid property name from <code>get_data_model_properties</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Conditional</td><td>The comparison value. For foreign key properties, provide the entity ID (GUID). Use the string <code>&quot;null&quot;</code> for null comparisons. Not required when <code>comparisonPropertyName</code> is set.</td></tr><tr><td><code>valueType</code></td><td>enum</td><td>Conditional</td><td><code>boolean</code>, <code>string</code>, <code>number</code>, or <code>null</code>. Use <code>null</code> when the value is null. Not required when <code>comparisonPropertyName</code> is set.</td></tr><tr><td><code>comparisonPropertyName</code></td><td>string</td><td>No</td><td>When set, compares <code>propertyName</code> against this property instead of <code>value</code>. Must be a valid property from <code>get_data_model_properties</code>.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Property-to-property comparison</p><p>To find records where one field exceeds another — for example, where <code>UpdatedDate</code> is after <code>CreatedDate</code> — set <code>propertyName</code> to <code>UpdatedDate</code>, <code>comparisonPropertyName</code> to <code>CreatedDate</code>, and <code>operator</code> to <code>GreaterThan</code>. When using <code>comparisonPropertyName</code>, omit <code>value</code> and <code>valueType</code>.</p></div><h4 id="paging" tabindex="-1">Paging <a class="header-anchor" href="#paging" aria-label="Permalink to &quot;Paging&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>pageNumber</code></td><td>integer</td><td>No</td><td>Page to retrieve, 1-based (default 1)</td></tr><tr><td><code>pageSize</code></td><td>integer</td><td>No</td><td>Items per page, 1–100 (default 25)</td></tr></tbody></table><p>The response includes <code>hasMore</code> (boolean) and <code>nextPage</code> (number or null). If <code>nextPage</code> is non-null, pass it as <code>pageNumber</code> in the next request to continue.</p><h4 id="sort-condition" tabindex="-1">Sort Condition <a class="header-anchor" href="#sort-condition" aria-label="Permalink to &quot;Sort Condition&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>propertyName</code></td><td>string</td><td>Yes</td><td>Property name from <code>get_data_model_properties</code></td></tr><tr><td><code>sortOrder</code></td><td>enum</td><td>No</td><td><code>Ascending</code> or <code>Descending</code> (default <code>Ascending</code>)</td></tr></tbody></table><hr><h3 id="get-entities-by-ids" tabindex="-1"><code>get_entities_by_ids</code> <a class="header-anchor" href="#get-entities-by-ids" aria-label="Permalink to &quot;`get_entities_by_ids`&quot;">​</a></h3><p>Retrieves one or more entities by their unique IDs from a specific Data Model. For a single entity, pass an array with one ID. Non-existent IDs are silently omitted from the results.</p><p>If a result is a File entity with an <code>externalFileLocation</code> property, use <code>get_file_text</code> to extract readable content.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr><tr><td><code>entityIds</code></td><td>GUID[]</td><td>Yes</td><td>Array of entity IDs to retrieve (1–50)</td></tr><tr><td><code>properties</code></td><td>string[]</td><td>No</td><td>Property names to include in results. Only these fields (plus <code>id</code>) are returned. Omit to return all fields.</td></tr></tbody></table><h2 id="saved-queries" tabindex="-1">Saved Queries <a class="header-anchor" href="#saved-queries" aria-label="Permalink to &quot;Saved Queries&quot;">​</a></h2><h3 id="get-saved-queries" tabindex="-1"><code>get_saved_queries</code> <a class="header-anchor" href="#get-saved-queries" aria-label="Permalink to &quot;`get_saved_queries`&quot;">​</a></h3><p>Returns all Saved Queries (Live Data Providers) accessible to the user. Each query includes its name, ID, connector info, data model info, and declared input parameters.</p><p><strong>Parameters:</strong> None</p><hr><h3 id="get-saved-query-details" tabindex="-1"><code>get_saved_query_details</code> <a class="header-anchor" href="#get-saved-query-details" aria-label="Permalink to &quot;`get_saved_query_details`&quot;">​</a></h3><p>Returns detailed metadata for a specific Saved Query, including its mapped fields (property names, types, and descriptions) filtered by user permissions. Must first call <code>get_saved_queries</code> to get the <code>savedQueryId</code>.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>savedQueryId</code></td><td>GUID</td><td>Yes</td><td>The Saved Query ID from <code>get_saved_queries</code></td></tr></tbody></table><hr><h3 id="execute-saved-query" tabindex="-1"><code>execute_saved_query</code> <a class="header-anchor" href="#execute-saved-query" aria-label="Permalink to &quot;`execute_saved_query`&quot;">​</a></h3><p>Executes a Saved Query by its ID with the provided input parameters. Must first call <code>get_saved_queries</code> to get the <code>savedQueryId</code> and declared inputs.</p><p>If results contain File entities with an <code>externalFileLocation</code> property, use <code>get_file_text</code> to extract readable content.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>savedQueryId</code></td><td>GUID</td><td>Yes</td><td>The Saved Query ID from <code>get_saved_queries</code></td></tr><tr><td><code>inputs</code></td><td>array</td><td>No</td><td>Input parameters matching <code>DeclaredInputs</code> from <code>get_saved_queries</code> (see below)</td></tr><tr><td><code>properties</code></td><td>string[]</td><td>No</td><td>Property names to include in results. Only these fields (plus <code>id</code>) are returned. Omit to return all fields.</td></tr></tbody></table><p><strong>Input Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>Yes</td><td>Input name from <code>DeclaredInputs</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Yes</td><td>Value for the input</td></tr></tbody></table><h2 id="data-entry" tabindex="-1">Data Entry <a class="header-anchor" href="#data-entry" aria-label="Permalink to &quot;Data Entry&quot;">​</a></h2><h3 id="get-data-entry-form" tabindex="-1"><code>get_data_entry_form</code> <a class="header-anchor" href="#get-data-entry-form" aria-label="Permalink to &quot;`get_data_entry_form`&quot;">​</a></h3><p>Retrieves a data entry form for a Data Model, optionally pre-populated with initial values. Must first call <code>get_data_models</code> to get a <code>dataModelId</code>. Send the output of this tool to <code>submit_data_entry_form</code> when complete.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID from <code>get_data_models</code></td></tr><tr><td><code>format</code></td><td>enum</td><td>Yes</td><td><code>AdaptiveCard</code> or <code>Json</code> — use the most appropriate format for the calling client</td></tr><tr><td><code>initialValues</code></td><td>array</td><td>No</td><td>Key-value pairs to pre-populate the form (see below)</td></tr></tbody></table><p><strong>Initial Values:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>Yes</td><td>Property name from <code>get_data_model_properties</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Yes</td><td>Initial value for the field</td></tr></tbody></table><hr><h3 id="submit-data-entry-form" tabindex="-1"><code>submit_data_entry_form</code> <a class="header-anchor" href="#submit-data-entry-form" aria-label="Permalink to &quot;`submit_data_entry_form`&quot;">​</a></h3><p>Submits a completed data entry form to create or update a record.</p><div class="danger custom-block"><p class="custom-block-title">Destructive</p><p>This tool creates or modifies records. The AI assistant will confirm with the user before submitting.</p></div><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>dataModelId</code></td><td>GUID</td><td>Yes</td><td>The Data Model ID — should match the one passed to <code>get_data_entry_form</code></td></tr><tr><td><code>system</code></td><td>enum</td><td>No</td><td>The submitting system: <code>Corbi</code>, <code>ChatGPT</code>, <code>Claude</code>, or <code>Copilot</code></td></tr><tr><td><code>formValues</code></td><td>array</td><td>Yes</td><td>Completed form values (see below)</td></tr></tbody></table><p><strong>Form Values:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>Yes</td><td>Property name from <code>get_data_model_properties</code></td></tr><tr><td><code>value</code></td><td>string</td><td>Yes</td><td>Submitted value for the field</td></tr></tbody></table><h2 id="file-extraction" tabindex="-1">File Extraction <a class="header-anchor" href="#file-extraction" aria-label="Permalink to &quot;File Extraction&quot;">​</a></h2><h3 id="get-file-text" tabindex="-1"><code>get_file_text</code> <a class="header-anchor" href="#get-file-text" aria-label="Permalink to &quot;`get_file_text`&quot;">​</a></h3><p>Extracts readable text from a document URL. Supports PDF, DOCX, PPTX, HTML, TXT, MD, CSV, JSON, and XML formats. Returns text in chunks — call repeatedly using the <code>nextOffset</code> value from the response until <code>hasMore</code> is <code>false</code>.</p><p><strong>Parameters:</strong></p><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>url</code></td><td>URL</td><td>Yes</td><td>The <code>externalFileLocation</code> URL from the entity</td></tr><tr><td><code>offset</code></td><td>integer</td><td>No</td><td>Start at <code>0</code>, then use <code>nextOffset</code> from the previous response (default <code>0</code>)</td></tr></tbody></table>',78)])])}const m=t(a,[["render",i]]);export{u as __pageData,m as default};
